// DROP 8 Refactor 019 — AI Humanization, Perception, Combat & Dialogue
// Windows CMD:
//   node --experimental-strip-types DROP8_refactor_019_ai_humanization_perception_combat_dialogue_patch_FIXED_v1.ts --dry-run
//   node --experimental-strip-types DROP8_refactor_019_ai_humanization_perception_combat_dialogue_patch_FIXED_v1.ts
//   node --experimental-strip-types DROP8_refactor_019_ai_humanization_perception_combat_dialogue_patch_FIXED_v1.ts --rollback "patch_backups\refactor_019_ai_humanization_perception_combat_dialogue\<timestamp>"
import { copyFileSync, cpSync, existsSync, mkdirSync, readFileSync, renameSync, rmSync, writeFileSync } from 'node:fs';
import { createHash } from 'node:crypto';
import { dirname, isAbsolute, join, relative, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { gunzipSync } from 'node:zlib';
import { spawnSync } from 'node:child_process';

type Entry={path:string;purpose:string;mode:'modify'|'create';beforeSha256:string;afterSha256:string;content:string};
type Payload={marker:string;entries:Entry[]};
type Manifest={patchId:string;patchFile:string;createdAt:string;projectRoot:string;files:Array<{path:string;existed:boolean;beforeSha256:string;eol:'LF'|'CRLF';bom:boolean}>;createdFiles:string[];generatedDirs:Array<{path:string;existed:boolean}>;balanceSnapshot:Record<string,string>};
const PATCH_ID='DROP8 Refactor 019 AI Humanization FIXED v1';
const PATCH_FILE='DROP8_refactor_019_ai_humanization_perception_combat_dialogue_patch_FIXED_v1.ts';
const BACKUP_NAME='refactor_019_ai_humanization_perception_combat_dialogue';
const PAYLOAD_B64='';
const payload=JSON.parse(gunzipSync(Buffer.from(PAYLOAD_B64,'base64')).toString('utf8')) as Payload;
const dryRun=process.argv.includes('--dry-run');
const rollbackIndex=process.argv.indexOf('--rollback');
const internal=process.env.DROP8_PATCH_INTERNAL_TEST==='1';
const forceFail=process.env.DROP8_PATCH_FORCE_FAIL==='1';
const sha=(data:string|Buffer)=>createHash('sha256').update(data).digest('hex');
const read=(path:string)=>readFileSync(path,'utf8');
const eol=(text:string):'LF'|'CRLF'=>text.includes('\r\n')?'CRLF':'LF';
const hasBom=(text:string)=>text.charCodeAt(0)===0xfeff;
const safe=(rel:string)=>{const value=rel.replace(/\\/g,'/');if(value.startsWith('/')||value.includes('..'))throw new Error(`안전하지 않은 경로: ${rel}`);return value;};
function findRoot(){const candidates=[process.cwd(),dirname(fileURLToPath(import.meta.url))];for(const start of candidates){let current=resolve(start);for(let i=0;i<8;i++){if(existsSync(join(current,'package.json'))&&existsSync(join(current,'server/src/rooms/Drop8Room.ts'))&&existsSync(join(current,'client/src/GameScene.ts'))&&existsSync(join(current,'shared/src/index.ts')))return current;const parent=dirname(current);if(parent===current)break;current=parent;}}throw new Error('DROP 8 프로젝트 루트를 찾지 못했습니다. 패치 파일을 프로젝트 루트에서 실행하세요.');}
function timestamp(){return new Date().toISOString().replace(/[-:]/g,'').replace(/\..+$/,'').replace('T','_');}
function atomicWrite(path:string,text:string){mkdirSync(dirname(path),{recursive:true});const temp=`${path}.drop8-ref019-${process.pid}.tmp`;writeFileSync(temp,text,'utf8');renameSync(temp,path);}
function captureBalances(root:string){const shared=read(join(root,'shared/src/index.ts')),wolf=read(join(root,'shared/src/werewolfSeason.ts'));const line=(name:string)=>shared.split(/\r?\n/).find((value)=>value.includes(name))?.trim()??'미검출';return{shotgun:line("shotgun:{"),flamethrower:line("flamethrower:{"),bazooka:line("bazooka:{"),motorcycle:line('export const MOTORCYCLE_BALANCE'),silver:line("silver_crossbow:{"),werewolf:wolf.split(/\r?\n/).find((value)=>value.includes('silverBoltDamage'))?.trim()??'미검출',adhesive:line("adhesive_sprayer:{")};}
function markerState(root:string){let applied=0,before=0;const conflicts:string[]=[];for(const entry of payload.entries){const target=join(root,safe(entry.path));if(entry.mode==='create'){if(!existsSync(target))before++;else if(sha(readFileSync(target))===entry.afterSha256)applied++;else conflicts.push(`${entry.path}(동명 파일 충돌)`);continue;}if(!existsSync(target)){conflicts.push(`${entry.path}(누락)`);continue;}const digest=sha(readFileSync(target));if(digest===entry.afterSha256)applied++;else if(digest===entry.beforeSha256)before++;else conflicts.push(`${entry.path}(분석 ZIP과 다른 내용)`);}return{applied,before,conflicts,total:payload.entries.length};}
function validatePackage(root:string){const pkg=JSON.parse(read(join(root,'package.json'))) as {scripts?:Record<string,string>};for(const script of ['typecheck','lint','test','build'])if(!pkg.scripts?.[script])throw new Error(`package.json 필수 script 누락: ${script}`);}
function validateProtectedValues(root:string){const source=read(join(root,'shared/src/index.ts')),room=read(join(root,'server/src/rooms/Drop8Room.ts')),wolf=read(join(root,'shared/src/werewolfSeason.ts'));const required=[['샷건 수동 밸런스',/shotgun:\{[^\n]*damage:15[^\n]*spread:\.18[^\n]*pellets:8/],['화염방사기 사거리',/flamethrower:\{[^\n]*range:420/],['바주카 탄속',/bazooka:\{[^\n]*projectileSpeed:900/],['오토바이 HP',/maxHp:180/],['은화살 산탄',/silver_crossbow:\{[^\n]*fireInterval:\.42[^\n]*magazine:4[^\n]*projectileSpeed:2100[^\n]*pellets:5/]] as const;for(const [name,pattern] of required)if(!pattern.test(source))throw new Error(`현재 수동 핫픽스 보호 검증 실패: ${name}`);if(!/silverBoltDamage:20/.test(wolf))throw new Error('은화살 늑대 피해 보호 검증 실패');if(!room.includes('target.werewolf.silverSlowUntil=Math.max'))throw new Error('점착 분사기 사람·늑대 감속 핫픽스가 감지되지 않습니다.');}
function backupAndWrite(root:string){const backup=join(root,'patch_backups',BACKUP_NAME,timestamp()),pre=join(backup,'preimage');mkdirSync(pre,{recursive:true});const manifest:Manifest={patchId:PATCH_ID,patchFile:PATCH_FILE,createdAt:new Date().toISOString(),projectRoot:root,files:[],createdFiles:[],generatedDirs:[],balanceSnapshot:captureBalances(root)};for(const entry of payload.entries){const rel=safe(entry.path),target=join(root,rel),existed=existsSync(target);if(existed){const original=readFileSync(target);const backupFile=join(pre,rel);mkdirSync(dirname(backupFile),{recursive:true});copyFileSync(target,backupFile);const text=original.toString('utf8');manifest.files.push({path:rel,existed:true,beforeSha256:sha(original),eol:eol(text),bom:hasBom(text)});}else{manifest.files.push({path:rel,existed:false,beforeSha256:'',eol:'LF',bom:false});manifest.createdFiles.push(rel);}}for(const rel of ['shared/dist','client/dist','server/build']){const target=join(root,rel),existed=existsSync(target);manifest.generatedDirs.push({path:rel,existed});if(existed){const dest=join(backup,'generated-preimage',rel);mkdirSync(dirname(dest),{recursive:true});cpSync(target,dest,{recursive:true,preserveTimestamps:true});}}writeFileSync(join(backup,'manifest.json'),JSON.stringify(manifest,null,2),'utf8');for(const entry of payload.entries)atomicWrite(join(root,safe(entry.path)),entry.content);return backup;}
function rollback(root:string,arg:string){const backup=isAbsolute(arg)?arg:resolve(root,arg),manifestPath=join(backup,'manifest.json');if(!existsSync(manifestPath))throw new Error(`manifest를 찾지 못했습니다: ${manifestPath}`);const manifest=JSON.parse(read(manifestPath)) as Manifest;if(manifest.patchId!==PATCH_ID)throw new Error(`다른 패치 백업입니다: ${manifest.patchId}`);for(const item of [...manifest.files].reverse()){const target=join(root,safe(item.path));if(item.existed){const source=join(backup,'preimage',safe(item.path));if(!existsSync(source))throw new Error(`백업 파일 누락: ${item.path}`);mkdirSync(dirname(target),{recursive:true});copyFileSync(source,target);}else rmSync(target,{force:true});}for(const dir of manifest.generatedDirs){const target=join(root,safe(dir.path));rmSync(target,{recursive:true,force:true});if(dir.existed){const source=join(backup,'generated-preimage',safe(dir.path));if(existsSync(source))cpSync(source,target,{recursive:true,preserveTimestamps:true});}}console.log(`[${PATCH_ID}] 롤백 완료: ${backup}`);}
function verifyAfter(root:string){for(const entry of payload.entries){const target=join(root,safe(entry.path));if(!existsSync(target)||sha(readFileSync(target))!==entry.afterSha256)throw new Error(`적용 후 무결성 실패: ${entry.path}`);}}
function run(label:string,command:string,root:string,log:string){console.log(`\n[${PATCH_ID}] ${label}\n> ${command}`);const result=spawnSync(command,{cwd:root,shell:true,encoding:'utf8',maxBuffer:64*1024*1024,env:process.env});const text=`\n### ${label}\n> ${command}\nexit=${result.status}\n${result.stdout??''}\n${result.stderr??''}\n`;writeFileSync(log,text,{encoding:'utf8',flag:'a'});if(result.stdout)process.stdout.write(result.stdout);if(result.stderr)process.stderr.write(result.stderr);if(result.error)throw result.error;if(result.status!==0)throw new Error(`${label} 실패 (exit=${result.status})`);}
const root=findRoot();process.chdir(root);console.log(`[${PATCH_ID}] 프로젝트 루트: ${root}`);if(rollbackIndex>=0){const arg=process.argv[rollbackIndex+1];if(!arg)throw new Error('--rollback 뒤에 백업 폴더를 입력하세요.');rollback(root,arg);process.exit(0);}validatePackage(root);const state=markerState(root);if(state.conflicts.length)throw new Error(`기준 코드 충돌: ${state.conflicts.join(', ')}`);if(state.applied===state.total){verifyAfter(root);console.log(`[${PATCH_ID}] 이미 정상 적용되어 있습니다.`);process.exit(0);}if(state.applied>0)throw new Error(`부분 적용 상태 감지: ${state.applied}/${state.total}. 억지로 진행하지 않습니다.`);validateProtectedValues(root);const balances=captureBalances(root);console.log(`[${PATCH_ID}] 현재 수동 밸런스 보호 결과:`);for(const [key,value] of Object.entries(balances))console.log(` - ${key}: ${value}`);console.log(`\n[${PATCH_ID}] 변경 예정 파일:`);for(const entry of payload.entries)console.log(` - [${entry.mode==='create'?'신규':'수정'}] ${entry.path} :: ${entry.purpose}`);console.log(`[${PATCH_ID}] Schema 변경: 없음`);console.log(`[${PATCH_ID}] 신규 네트워크 메시지: aiDialogue`);console.log(`[${PATCH_ID}] 예상 백업: patch_backups\\${BACKUP_NAME}\\<timestamp>`);console.log(`[${PATCH_ID}] 검증: typecheck -> lint -> Refactor 019 집중 테스트 -> 채팅/Room 회귀 -> 전체 test -> build -> git diff --check`);if(dryRun){console.log(`\n[${PATCH_ID}] dry-run 성공: 실제 파일과 백업을 만들지 않았습니다.`);process.exit(0);}const backup=backupAndWrite(root),log=join(backup,'verification-log.txt');writeFileSync(log,'','utf8');try{verifyAfter(root);if(forceFail)throw new Error('DROP8_PATCH_FORCE_FAIL=1 강제 실패');if(!internal){run('TypeScript typecheck','pnpm run typecheck',root,log);run('ESLint','pnpm run lint',root,log);run('Refactor 019 공용 집중 테스트','pnpm --filter @drop8/shared exec vitest run tests/refactor019-ai-humanization.test.ts --reporter=verbose',root,log);run('Refactor 019 서버 집중 테스트','pnpm --filter @drop8/server exec vitest run tests/refactor019-ai-humanization.test.ts --pool=threads --maxWorkers=1 --no-file-parallelism --testTimeout=30000 --hookTimeout=30000 --reporter=verbose',root,log);run('채팅·Room·수풀·창문 회귀 테스트','pnpm --filter @drop8/server exec vitest run tests/chat-input.test.ts tests/room.test.ts tests/refactor013h1-nested-window-dock8-loot.test.ts tests/refactor018-werewolf-combat.test.ts --pool=threads --maxWorkers=1 --no-file-parallelism --testTimeout=30000 --hookTimeout=30000 --reporter=verbose',root,log);run('전체 테스트','pnpm run test',root,log);run('전체 빌드','pnpm run build',root,log);run('Refactor 019 대상 git diff check',`git diff --check -- ${payload.entries.map((entry)=>`"${entry.path}"`).join(' ')}`,root,log);}else console.log(`[${PATCH_ID}] 내부 복제본 검증 모드: pnpm 명령 생략`);console.log(`\n[${PATCH_ID}] 적용 성공`);console.log(`[${PATCH_ID}] 백업: ${backup}`);console.log(`[${PATCH_ID}] 롤백 CMD: node --experimental-strip-types ${PATCH_FILE} --rollback "${relative(root,backup)}"`);}catch(error){console.error(`\n[${PATCH_ID}] 검증 실패. 전체 자동 롤백합니다.`);try{rollback(root,backup);}catch(rollbackError){console.error('자동 롤백 오류',rollbackError);}console.error(`[${PATCH_ID}] 백업: ${backup}`);throw error;}
